	@Inject
	public PogLGrammarAccess(GrammarProvider grammarProvider,
			TerminalsGrammarAccess gaTerminals) {
		this.grammar = internalFindGrammar(grammarProvider);
		this.gaTerminals = gaTerminals;
		this.pProgram = new ProgramElements();
		this.pModel = new ModelElements();
		this.pState = new StateElements();
		this.pFstate = new FstateElements();
		this.pFstate_name = new Fstate_nameElements();
		this.pItem = new ItemElements();
		this.pFitem = new FitemElements();
		this.pFitem_name = new Fitem_nameElements();
		this.pGoto = new GotoElements();
		this.pShow = new ShowElements();
		this.pOperation = new OperationElements();
		this.pOperations = new OperationsElements();
		this.pFOperations = new FOperationsElements();
		this.pComparisonOperators = new ComparisonOperatorsElements();
		this.pCheck = new CheckElements();
		this.pFCheck = new FCheckElements();
		this.pFCheck_item = new FCheck_itemElements();
		this.pFComparison_Operators = new FComparison_OperatorsElements();
		this.pFINT = new FINTElements();
		this.pFthen = new FthenElements();
		this.pFThenOperations = new FThenOperationsElements();
		this.pAction = new ActionElements();
	}
	
	protected Grammar internalFindGrammar(GrammarProvider grammarProvider) {
		Grammar grammar = grammarProvider.getGrammar(this);
		while (grammar != null) {
			if ("org.xtext.poglanguage.pogl.PogL".equals(grammar.getName())) {
				return grammar;
			}
			List<Grammar> grammars = grammar.getUsedGrammars();
			if (!grammars.isEmpty()) {
				grammar = grammars.iterator().next();
			} else {
				return null;
			}
		}
		return grammar;
	}
	
